This section contains the contents of the repository's files.


name: Deploy to main-kanak

on:
  push:
    branches:
      - main
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, jenkins-server]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4

      - name: Deploy latest code
        run: |
          echo ">>> Switching to project directory"
          cd /home/ubuntu/api_code/kanakloans-webview/

          echo ">>> Fetching latest code from main branch"
          git pull origin main

          echo ">>> Install dependency"
          npm install --legacy-peer-deps
          CI=false npm run build

          echo ">>> rm from s3"
          aws s3 rm s3://pl.kanakloans.com --recursive --profile kanak

          echo ">>> upload on s3"
          aws s3 cp dist/ s3://pl.kanakloans.com/ --recursive --profile kanak

          aws cloudfront create-invalidation --distribution-id E1VI3ZFLBXWWL6 --paths "/*" --profile kanak

          echo ">>> Showing last 10 commits"
          git log -10 --oneline
          echo ">>> Deployment completed successfully!"



